package com.assetflow.nexora.entity;
import jakarta.persistence.*; @Entity @Table(name="category_custom_fields",uniqueConstraints=@UniqueConstraint(columnNames={"category_id","field_name"})) public class CategoryCustomField { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) @Column(name="field_id") public Long id; @Column(name="category_id",nullable=false) public Long categoryId; @Column(name="field_name",nullable=false,length=100) public String fieldName; @Column(name="field_type",nullable=false,length=20) public String fieldType="Text"; @Column(name="is_required",nullable=false) public boolean required; }
